private isDuplicateDay() {
  return (
    //day is one of the non rendered duplicate days
    (this.props.monthShowsDuplicateDaysEnd && this.isAfterMonth()) ||
    (this.props.monthShowsDuplicateDaysStart && this.isBeforeMonth())
  );
}

